1	type Customer = {
2	  yearsAsCustomer: number;
3	  quoteCount: number;
4	};
5	
6	type Item = {
7	  type: string;
8	  material: string;
9	  enchantment: number;
10	  cursed: boolean;
11	};
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	};
20	
21	const PROCESSING_FEE = 5;
22	const FIRST_INSURANCE_RATE = 0.1;
23	
24	export function quote(customer: Customer, items: Item[]): number {
25	  if (items.length === 0) return PROCESSING_FEE;
26	  const basePremium = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
27	  return basePremium + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
28	}
29	
